VALUES
  ('social-worker-moex-06350', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年福利與權益保障法，有關兒童及少年收出養之規定，下列敘述何者錯誤？', '["從事收出養媒合服務，以經主管機關許可之財團法人與社團法人、公私立兒童及少年安置、教養機構 為限", "收出養媒合服務者應評估並安排收養人與兒童、少年先行共同生活或漸進式接觸", "收出養媒合服務者從事收出養媒合服務，得向收養人收取服務費用", "中央主管機關應保存出養人、收養人及被收養兒童及少年之身分、健康等相關資訊之檔案"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06351', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年福利與權益保障法，有關居家式托育服務之規定，下列敘述何者正確？', '["居家式托育服務係指兒童由其三親等內親屬以外之人員，於居家環境中提供收費之托育服務", "居家式托育服務提供者，應向中央主管機關辦理登記，統一管理", "居家式托育服務提供者年齡應年滿18歲，並具有相關證照", "曾受監護或輔助宣告者，一律不得擔任居家式托育服務提供者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06352', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關社會救助法規定，有工作能力未就業者的工作收入，除依基本工資核算外，下列敘述何者正確？', '["經公立就業服務機構認定失業者，其失業或參加職業訓練期間得不計算工作收入", "50歲以上經公立就業服務機構媒介工作5次以上未媒合成功、參加政府主辦或委辦全日制職業訓練，其 失業或參加職業訓練期間得不計算工作收入", "失業者在失業期間所領取之失業給付或職業訓練生活津貼，將不併入其他收入計算", "依建教生權益保障法規定，參加建教合作計畫所領取之職業技能訓練生活津貼，則應予列計工作收入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06353', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '有關家庭暴力防治法所定家庭成員之敘述，不包含下列何項人員及其未成年子女？', '["配偶或前配偶", "現有或曾有同居關係、家長家屬或家屬間關係者", "現為或曾為直系血親或直系姻親", "現為或曾為三親等以內之旁系血親或旁系姻親"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "52794989f8a5", "answer_pdf_sha1": "6e67d7a4aa32", "source_family": "moex-gov-tw", "moex": {"exam_code": "104100", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第二次專技中醫師分階段考試營養師心理師護理師社會工作師考試法醫師語言治療師聽力師牙體技術師考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
